#include "gtest/gtest.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void SetUp() override {
    ON_CALL(decoder_callbacks_, streamInfo()).WillByDefault(ReturnRef(stream_info_));
    ON_CALL(encoder_callbacks_, streamInfo()).WillByDefault(ReturnRef(stream_info_));
  }

  void initializeFilter(const std::string& config_yaml = "{}") {
    envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection config;
    TestUtility::loadFromYaml(config_yaml, config);

    filter_config_ = std::make_shared<FilterConfig>(config);
    filter_ = std::make_unique<CustomHeaderInjectionFilter>(filter_config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  StreamInfo::StreamInfoImpl stream_info_{
      absl::make_unique<Http::RequestHeaderMapImpl>(), SystemTime::now()};

  std::unique_ptr<CustomHeaderInjectionFilter> filter_;
  FilterConfigSharedPtr filter_config_;
};

TEST_F(CustomHeaderInjectionFilterTest, EmptyConfig) {
  initializeFilter();
  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(headers, false));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectRequestHeaders) {
  const std::string config_yaml = R"EOF(
request_headers_to_add:
  - header:
      key: x-custom-request
      value: request-value
  - header:
      key: x-another-request
      value: another-value
)EOF";

  initializeFilter(config_yaml);
  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(headers, false));

  EXPECT_EQ("request-value", headers.get_("x-custom-request"));
  EXPECT_EQ("another-value", headers.get_("x-another-request"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectResponseHeaders) {
  const std::string config_yaml = R"EOF(
response_headers_to_add:
  - header:
      key: x-custom-response
      value: response-value
  - header:
      key: x-another-response
      value: another-value
)EOF";

  initializeFilter(config_yaml);
  Http::TestResponseHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(headers, false));

  EXPECT_EQ("response-value", headers.get_("x-custom-response"));
  EXPECT_EQ("another-value", headers.get_("x-another-response"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectBothRequestAndResponseHeaders) {
  const std::string config_yaml = R"EOF(
request_headers_to_add:
  - header:
      key: x-request
      value: request
response_headers_to_add:
  - header:
      key: x-response
      value: response
)EOF";

  initializeFilter(config_yaml);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("request", request_headers.get_("x-request"));

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("response", response_headers.get_("x-response"));
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

